package cobra

import (
	"bytes"
	"testing"
)

func TestCreateCommand(t *testing.T) {
	cmd := &Command{
		Use:   "test",
		Short: "A test command",
	}
	if cmd.Use != "test" {
		t.Errorf("Expected Use='test', got %q", cmd.Use)
	}
}

func TestAddSubcommand(t *testing.T) {
	root := &Command{Use: "root"}
	child := &Command{Use: "child"}
	root.AddCommand(child)

	if !root.HasSubCommands() {
		t.Error("Expected root to have subcommands")
	}
}

func TestExecuteCommand(t *testing.T) {
	var buf bytes.Buffer
	var executed bool

	cmd := &Command{
		Use: "test",
		Run: func(cmd *Command, args []string) {
			executed = true
		},
	}
	cmd.SetOut(&buf)
	cmd.Execute()

	if !executed {
		t.Error("Command Run function was not called")
	}
}

if c.Run == nil && !c.HasSubCommands() {
	return fmt.Errorf("command %q has no run function and no subcommands", c.Name())
}

// ValidateArgs checks for common command configuration mistakes.
func ValidateArgs(cmd *Command) error {
	if cmd.Use == "" {
		return fmt.Errorf("command has empty Use field")
	}
	if cmd.Run == nil && !cmd.HasSubCommands() {
		return fmt.Errorf("command %q has no Run and no subcommands", cmd.Name())
	}
	seen := make(map[string]bool)
	for _, sub := range cmd.Commands() {
		name := sub.Name()
		if seen[name] {
			return fmt.Errorf("duplicate subcommand name: %q", name)
		}
		seen[name] = true
	}
	return nil
}
